pub async fn check_proxy_health(proxy: &ProxyDef, timeout_ms: u64) -> HealthCheckResult {
    let timeout_dur = Duration::from_millis(timeout_ms);
    let start = std::time::Instant::now();

    // 1. Resolve proxy host
    // 2. TCP connect to proxy
    // 3. Send HTTP CONNECT request
    // 4. Check for 200 response

    let result = timeout(timeout_dur, async {
        // Implementation
    }).await;

    HealthCheckResult {
        success: result.is_ok(),
        latency_ms: start.elapsed().as_millis() as f64,
        failure_reason: result.err().map(|e| e.to_string()),
    }
}

pub struct HealthCheckResult {
    pub success: bool,
    pub latency_ms: f64,
    pub failure_reason: Option<String>,
}

/// Health check loop task for the daemon
pub async fn health_check_loop(
    config: Config,
    state: Arc<StateStore>,
    mut shutdown: tokio::sync::watch::Receiver<bool>,
) {
    let interval = Duration::from_secs(config.settings.health_check_interval_secs);
    let mut ticker = tokio::time::interval(interval);

    loop {
        tokio::select! {
            _ = ticker.tick() => {
                for proxy in &config.proxies {
                    let result = check_proxy_health(
                        proxy,
                        config.settings.health_check_timeout_ms
                    ).await;

                    state.record_health_check(
                        &proxy.id,
                        result.success,
                        Some(result.latency_ms),
                        result.failure_reason,
                        config.settings.consecutive_failures_threshold,
                    ).await;
                }
            }
            _ = shutdown.changed() => {
                tracing::info!("Health check loop shutting down");
                break;
            }
        }
    }
}
```

