/// Check if failover should occur and perform it
pub async fn check_and_perform_failover(
    config: &Config,
    state: &StateStore,
) -> Option<FailoverEvent> {
    // 1. Get current active proxy
    let active = config.active_proxy.as_ref()?;

    // 2. Check if active proxy is unhealthy
    let active_health = state.get_health_status(active).await;
    if active_health != HealthStatus::Unhealthy {
        return None; // No failover needed
    }

    // 3. Find best healthy alternative
    let alternative = find_best_healthy_proxy(config, state, active).await?;

    // 4. Perform failover (update config/state)
    Some(FailoverEvent {
        from_proxy: active.clone(),
        to_proxy: alternative,
        reason: "health check failure".to_string(),
    })
}

/// Find the highest-priority healthy proxy (excluding current)
async fn find_best_healthy_proxy(
    config: &Config,
    state: &StateStore,
    exclude: &str,
) -> Option<String> {
    let mut candidates: Vec<_> = config.proxies.iter()
        .filter(|p| p.id != exclude)
        .collect();

    // Sort by priority (lower = higher priority)
    candidates.sort_by_key(|p| p.priority.unwrap_or(100));

    for proxy in candidates {
        let health = state.get_health_status(&proxy.id).await;
        if health == HealthStatus::Healthy {
            return Some(proxy.id.clone());
        }
    }

    None // No healthy alternatives
}

pub struct FailoverEvent {
    pub from_proxy: String,
    pub to_proxy: String,
    pub reason: String,
}
```

