```rust
pub async fn check_and_perform_failback(
    config: &Config,
    state: &StateStore,
    failover_state: &mut FailoverState,
) -> Option<FailbackEvent> {
    // 1. Check if we're in a failed-over state
    let original = failover_state.original_proxy.as_ref()?;

    // 2. Check if original is now healthy
    let original_health = state.get_health_status(original).await;
    if original_health != HealthStatus::Healthy {
        failover_state.recovery_detected_at = None;
        return None;
    }

    // 3. Track recovery time
    let now = Utc::now();
    let recovery_at = failover_state.recovery_detected_at
        .get_or_insert(now);

    // 4. Check if delay has passed
    let delay = Duration::from_secs(config.settings.failback_delay_secs);
    let elapsed = now.signed_duration_since(*recovery_at);
    if elapsed < chrono::Duration::from_std(delay).unwrap() {
        return None; // Still waiting
    }

    // 5. Perform failback
    let current = &config.active_proxy;
    failover_state.original_proxy = None;
    failover_state.recovery_detected_at = None;

    Some(FailbackEvent {
        from_proxy: current.clone().unwrap_or_default(),
        to_proxy: original.clone(),
    })
}
```

