fn format_health_status(status: HealthStatus) -> ColoredString {
    match status {
        HealthStatus::Healthy => "✓ Healthy".green(),
        HealthStatus::Degraded => "⚠ Degraded".yellow(),
        HealthStatus::Unhealthy => "✗ Unhealthy".red(),
        HealthStatus::Unknown => "? Unknown".dimmed(),
    }
}

fn format_time_ago(dt: Option<DateTime<Utc>>) -> String {
    dt.map(|t| {
        let ago = Utc::now().signed_duration_since(t);
        if ago.num_seconds() < 60 {
            format!("{}s ago", ago.num_seconds())
        } else if ago.num_minutes() < 60 {
            format!("{}m ago", ago.num_minutes())
        } else {
            format!("{}h ago", ago.num_hours())
        }
    }).unwrap_or_else(|| "never".to_string())
}
