## Problem
Current architecture loads config.active_proxy once at startup. Failover requires changing the active proxy at runtime, but:
- Modifying config file during operation is error-prone
- Config file should represent user intent, not runtime state
- Need atomic updates without file I/O

## Solution: RuntimeState

### Data Structure
```rust
// src/state.rs

use std::sync::Arc;
use tokio::sync::RwLock;

/// Runtime state that can change during daemon operation
/// Separate from Config (user intent) and StateStore (persistent stats)
#[derive(Debug)]
pub struct RuntimeState {
    /// Currently effective proxy (may differ from config during failover)
    effective_proxy: Arc<RwLock<Option<String>>>,

    /// Original active proxy from config (for failback)
    original_proxy: Option<String>,

    /// When current failover state began (None if no active failover)
    failover_at: Option<DateTime<Utc>>,

    /// When last failover/failback occurred (for min interval check)
    last_switch_at: Option<DateTime<Utc>>,

    /// Recovery detection timestamp (for failback delay)
    recovery_detected_at: Option<DateTime<Utc>>,
}

impl RuntimeState {
    /// Create from config on daemon startup
    pub fn from_config(config: &Config) -> Self {
        Self {
            effective_proxy: Arc::new(RwLock::new(config.active_proxy.clone())),
            original_proxy: config.active_proxy.clone(),
            failover_at: None,
            last_switch_at: None,
            recovery_detected_at: None,
        }
    }

    /// Get currently effective proxy (may be failover target)
    pub async fn get_effective_proxy(&self) -> Option<String> {
        self.effective_proxy.read().await.clone()
    }

    /// Check if we're in a failover state
    pub fn is_failed_over(&self) -> bool {
        self.failover_at.is_some()
    }

    /// Perform failover to a new proxy
    pub async fn failover_to(&self, new_proxy: &str) -> Result<()> {
        let mut effective = self.effective_proxy.write().await;
        *effective = Some(new_proxy.to_string());
        self.failover_at = Some(Utc::now());
        self.last_switch_at = Some(Utc::now());
        self.recovery_detected_at = None;
        Ok(())
    }

    /// Perform failback to original proxy
    pub async fn failback(&self) -> Result<()> {
        let mut effective = self.effective_proxy.write().await;
        *effective = self.original_proxy.clone();
        self.failover_at = None;
        self.last_switch_at = Some(Utc::now());
        self.recovery_detected_at = None;
        Ok(())
    }

    /// Record that original proxy has recovered (start failback timer)
    pub fn record_recovery_detected(&mut self) {
        if self.recovery_detected_at.is_none() {
            self.recovery_detected_at = Some(Utc::now());
        }
    }

    /// Clear recovery detection (original failed again)
    pub fn clear_recovery_detected(&mut self) {
        self.recovery_detected_at = None;
    }

    /// Check if enough time has passed for failback
    pub fn failback_delay_passed(&self, delay_secs: u64) -> bool {
        self.recovery_detected_at
            .map(|t| Utc::now().signed_duration_since(t).num_seconds() >= delay_secs as i64)
            .unwrap_or(false)
    }

    /// Check if enough time has passed since last switch (flapping prevention)
    pub fn can_switch(&self, min_interval_secs: u64) -> bool {
        self.last_switch_at
            .map(|t| Utc::now().signed_duration_since(t).num_seconds() >= min_interval_secs as i64)
            .unwrap_or(true)
    }
}
